const staticData = $getWorkflowStaticData('global');

if (!staticData.processedKeys) {
  staticData.processedKeys = {};
}

const recordKey = String($input.item.json.record_key).trim().toLowerCase();

// Check if key exists — works for both boolean true (old) and object (new)
const isDuplicate = staticData.processedKeys[recordKey] !== undefined;

// Reserve the slot immediately
if (!isDuplicate) {
  staticData.processedKeys[recordKey] = 'reserved';
}

return [{
  json: {
    ...$input.item.json,
    duplicate: isDuplicate
  }
}];

const staticData = $getWorkflowStaticData('global');

if (!staticData.processedKeys) {
  staticData.processedKeys = {};
}

const recordKey = String($input.item.json.record_key).trim().toLowerCase();

// Overwrite the boolean with a richer object
staticData.processedKeys[recordKey] = {
  status: 'success',
  run_id: $input.item.json.run_id,
  saved_at: new Date().toISOString(),
  company_name: $input.item.json.company_name
};

return [{
  json: {
    ...$input.item.json,
    storage_written: true
  }
}];
